        RealsenseWanderObstacleAvoidance node;
        node.run();
        return 0;
    } catch (const std::exception& exc) {
        ROS_FATAL("Failed to start realsense_wander_obstacle_avoidance: %s", exc.what());
        return 1;
    }
}

